// It sets up input and captures output for a program that reads from stdin and writes to stdout.
// The student's program (containing 'int main()') is expected to be compiled and executed.

#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <iomanip>
#include <cstdlib> // For system() - conceptual example

// Helper to capture stdout (not used directly in this conceptual driver, but for context)
struct CaptureOutput {
    std::stringstream oss;
    std::streambuf* oldCout;
    CaptureOutput() : oldCout(std::cout.rdbuf()) {
        std::cout.rdbuf(oss.rdbuf());
    }
    ~CaptureOutput() {
        std::cout.rdbuf(oldCout);
    }
    std::string getOutput() const { return oss.str(); }
};

// Helper to provide stdin (not used directly in this conceptual driver, but for context)
struct SimulateInput {
    std::istringstream iss;;
    std::streambuf* oldCin;
    SimulateInput(const std::string& input) : oldCin(std::cin.rdbuf()) {
        iss.str(input);
        std::cin.rdbuf(iss.rdbuf());
    }
    ~SimulateInput() { std::cin.rdbuf(oldCin); }
};

